  ('elementary-0a2fc18c-moex-00172', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '有關薪資收入（earnings），下列敘述何者錯誤？', '["通貨膨脹率通常大於零，故一國平均的名目薪資收入通常會逐年提高", "在物價上漲時期，一國的平均實質薪資收入不會高於其平均名目薪資", "若勞工領到的薪資收入提高，代表其購買力的提升", "實質薪資收入的提高通常伴隨著勞動生產力的提高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
